rule.query:
{
  "selection": {
    "CommandLine|startswith": [
      "sh -c ",
      "bash -c "
    ]
  },
  "selection_exec": [
    {
      "CommandLine|contains": [
        "| bash ",
        "| sh ",
        "|bash ",
        "|sh "
      ]
    },
    {
      "CommandLine|endswith": [
        "| bash",
        "| sh",
        "|bash",
        " |sh"
      ]
    }
  ],
  "condition": "all of selection*"
}
